unitsize(1.5 cm);

pair A, B, C, D, E, F, G;

A = (0,0);
B = (1,1);
C = (1,0.5);
D = (2.5,0.5);
E = (2.5,-0.5);
F = (1,-0.5);
G = (1,-1);

draw(A--B--C--D--E--F--G--cycle);

