label("$B$", B, NE);
label("$C$", C, S);
label("$D$", D, NE);
label("$E$", E, SE);
label("$F$", F, N);
label("$G$", G, SE);
label("$5$", (B + C)/2, dir(0));
label("$20$", (C + D)/2, N);
label("$10$", (D + E)/2, dir(0));
label("$20$", (E + F)/2, S);
label("$5$", (F + G)/2, dir(0));
[/asy]

